import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { toast } from "react-toastify";
import Modal from "../components/Modal";

function Admin() {
  const user = useSelector((state) => state.auth.user);
  const [users, setUsers] = useState([]);
  const [modal, setModal] = useState({ isOpen: false, userId: null, action: null });
  const [className, setClassName] = useState("");
  const [classes, setClasses] = useState([]);

  useEffect(() => {
    fetch("http://localhost:3001/users")
      .then((res) => res.json())
      .then((data) => setUsers(data.filter((u) => u.id !== user.id)))
      .catch((error) => toast.error("Ошибка загрузки пользователей"));
    fetch("http://localhost:3001/classes")
      .then((res) => res.json())
      .then((data) => setClasses(data))
      .catch((error) => toast.error("Ошибка загрузки классов"));
  }, [user.id]);

  async function handleBan(userId, isBanned) {
    const response = await fetch(`http://localhost:3001/users/${userId}`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ isBanned: !isBanned }),
    });

    if (response.ok) {
      setUsers(users.map((u) => (u.id === userId ? { ...u, isBanned: !isBanned } : u)));
      await fetch("http://localhost:3001/notifications", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          userId,
          message: isBanned ? "Ваш бан снят." : "Вы забанены администратором.",
          createdAt: new Date().toISOString(),
        }),
      });
      toast.success(isBanned ? "Бан снят!" : "Пользователь забанен!");
    } else {
      toast.error("Не удалось изменить статус бана");
    }
  }

  async function handleRoleChange(userId, newRole) {
    if (newRole === "admin") {
      const adminResponse = await fetch("http://localhost:3001/users?role=admin");
      const admins = await adminResponse.json();
      if (admins.length >= 2 && !admins.some((a) => a.id === userId)) {
        toast.error("Максимальное количество администраторов (2) уже достигнуто");
        return;
      }
    }

    const response = await fetch(`http://localhost:3001/users/${userId}`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ role: newRole }),
    });

    if (response.ok) {
      setUsers(users.map((u) => (u.id === userId ? { ...u, role: newRole } : u)));
      toast.success("Роль обновлена!");
    } else {
      toast.error("Не удалось обновить роль");
    }
  }

  async function handleCreateClass(e) {
    e.preventDefault();
    if (!className) {
      toast.error("Введите название класса");
      return;
    }

    const existingClass = classes.find((c) => c.name === className);
    if (existingClass) {
      toast.error("Класс с таким именем уже существует");
      return;
    }

    const response = await fetch("http://localhost:3001/classes", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name: className }),
    });

    if (response.ok) {
      const newClass = await response.json();
      setClasses([...classes, newClass]);
      setClassName("");
      toast.success("Класс успешно создан!");
    } else {
      toast.error("Не удалось создать класс");
    }
  }

  if (user?.role !== "admin") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">Панель администратора</h1>
      <div className="row">
        <div className="col-md-6">
          <div className="card shadow mb-4">
            <div className="card-body">
              <h2 className="card-title">Создать класс</h2>
              <form onSubmit={handleCreateClass}>
                <div className="mb-3">
                  <label htmlFor="className" className="form-label">Название класса</label>
                  <input
                    type="text"
                    id="className"
                    className="form-control"
                    value={className}
                    onChange={(e) => setClassName(e.target.value)}
                    required
                  />
                </div>
                <button type="submit" className="btn btn-primary w-100">Создать класс</button>
              </form>
              {classes.length > 0 && (
                <div className="mt-3">
                  <h5>Существующие классы:</h5>
                  <ul className="list-group">
                    {classes.map((cls) => (
                      <li key={cls.id} className="list-group-item">{cls.name}</li>
                    ))}
                  </ul>
                </div>
              )}
            </div>
          </div>
        </div>
        <div className="col-md-6">
          <div className="card shadow">
            <div className="card-body">
              <h2 className="card-title">Управление пользователями</h2>
              {users.length === 0 ? (
                <p>Пользователи отсутствуют</p>
              ) : (
                <ul className="list-group">
                  {users.map((u) => (
                    <li key={u.id} className="list-group-item d-flex align-items-center">
                      <div className="flex-grow-1">
                        <strong>{u.name}</strong> ({u.email})<br />
                        Роль: {u.role}<br />
                        Класс: {u.classId ? classes.find((c) => c.id === u.classId)?.name || "Неизвестный" : "Нет"}<br />
                        Статус: {u.isBanned ? "Забанен" : "Активен"}
                      </div>
                      <div>
                        <select
                          value={u.role}
                          onChange={(e) => handleRoleChange(u.id, e.target.value)}
                          className="form-select w-auto me-2"
                        >
                          <option value="student">Студент</option>
                          <option value="teacher">Учитель</option>
                          <option value="admin">Администратор</option>
                        </select>
                        <button
                          className={`btn btn-${u.isBanned ? "success" : "danger"} btn-sm`}
                          onClick={() => setModal({ isOpen: true, userId: u.id, action: u.isBanned ? "unban" : "ban" })}
                        >
                          {u.isBanned ? "Снять бан" : "Забанить"}
                        </button>
                      </div>
                    </li>
                  ))}
                </ul>
              )}
            </div>
          </div>
        </div>
      </div>
      <Modal
        isOpen={modal.isOpen}
        onClose={() => setModal({ isOpen: false, userId: null, action: null })}
        onConfirm={() => {
          handleBan(modal.userId, modal.action === "ban");
          setModal({ isOpen: false, userId: null, action: null });
        }}
        message={`Вы уверены, что хотите ${modal.action === "ban" ? "забанить" : "снять бан с"} этого пользователя?`}
      />
    </div>
  );
}

export default Admin;
